class Solution:
    def minimumDeletions(self, s):
        n = len(s)
        best = n
        b_count = 0
        prefix_b = [0] * (n + 1)
        for i, ch in enumerate(s):
            prefix_b[i + 1] = prefix_b[i] + (1 if ch == 'b' else 0)
        total_a = sum(1 for ch in s if ch == 'a')
        prefix_a_seen = 0
        for i in range(n + 1):
            b_before = prefix_b[i]
            a_from_i = total_a - prefix_a_seen
            cost = b_before + a_from_i
            if cost < best:
                best = cost
            if i < n and s[i] == 'a':
                prefix_a_seen += 1
        return best

